t.script:
            //
(function(){
document.addEventListener('DOMContentLoaded', function(){

    var BASE_URL  = '/my/employee/certification';
    var csrfToken = '';
    var pendingChanges = [];
    var tempIdCounter  = -1;

    var csrfEl = document.querySelector('input[name="csrf_token"]');
    if (csrfEl) csrfToken = csrfEl.value;

    /* Fix last-updated timezone */
    (function(){
        var el = document.getElementById('certLastUpdated');
        if (!el) return;
        var raw = (el.textContent || '').trim().replace(/\u00a0/g,' ');
        if (!raw || raw === 'Never') return;
        try {
            var m = raw.match(/(\d{1,2})\s+(\w+),?\s+(\d{4})\s+at\s+(\d{1,2}):(\d{2})\s*(AM|PM)/i);
            if (!m) return;
            var months={jan:0,feb:1,mar:2,apr:3,may:4,jun:5,jul:6,aug:7,sep:8,oct:9,nov:10,dec:11};
            var hr=parseInt(m[4],10), isPM=m[6].toUpperCase()==='PM';
            if(isPM&&hr<12)hr+=12; if(!isPM&&hr===12)hr=0;
            var dt=new Date(Date.UTC(parseInt(m[3],10),months[m[2].toLowerCase().substring(0,3)],parseInt(m[1],10),hr,parseInt(m[5],10)));
            if(!isNaN(dt.getTime()))
                el.textContent=dt.toLocaleString(undefined,{day:'2-digit',month:'short',year:'numeric',hour:'2-digit',minute:'2-digit',hour12:true});
        } catch(e) {}
    })();

    /* Helpers */
    function showMsg(text, type) {
        var c=document.getElementById('certMessageContainer');
        var s=document.getElementById('certSuccessMessage');
        var er=document.getElementById('certErrorMessage');
        s.style.display='none'; s.classList.remove('show');
        er.style.display='none'; er.classList.remove('show');
        if(type==='success'||type==='info'){
            document.getElementById('certSuccessText').textContent=text;
            s.style.display='block'; s.classList.add('show');
        } else {
            document.getElementById('certErrorText').textContent=text;
            er.style.display='block'; er.classList.add('show');
        }
        c.style.display='block';
        c.scrollIntoView({behavior:'smooth'});
        setTimeout(function(){s.classList.remove('show');er.classList.remove('show');},6000);
    }

    function formatDate(val) {
        if (!val) return '';
        var p=val.split('-');
        if(p.length!==3) return val;
        var months=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
        return parseInt(p[2],10)+' '+months[parseInt(p[1],10)-1]+' '+p[0];
    }

    function updatePendingBadge() {
        var badge=document.getElementById('certPendingBadge');
        var count=document.getElementById('certPendingCount');
        if(pendingChanges.length>0){count.textContent=pendingChanges.length;badge.style.display='block';}
        else badge.style.display='none';
    }

    function getRow(rowId) { return document.querySelector('#certTableBody tr[data-id="'+rowId+'"]'); }

    function clearRowBadge(row){ var b=row.querySelector('.cert-staged-badge'); if(b) b.remove(); }

    function addRowBadge(row,type){
        clearRowBadge(row);
        var labels={add:'New',edit:'Edited',delete:'To Delete'};
        var classes={add:'badge-staged-add',edit:'badge-staged-edit',delete:'badge-staged-delete'};
        var span=document.createElement('span');
        span.className='cert-staged-badge '+classes[type];
        span.textContent=labels[type];
        row.querySelector('.col-skill-name').appendChild(span);
    }

    function escHtml(str){
        return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
    }

    function openModal(id){document.getElementById(id).style.display='flex';}
    function closeModal(id){document.getElementById(id).style.display='none';}

    /* File input labels */
    document.getElementById('addFileInput').addEventListener('change',function(){
        var l=document.getElementById('addAttachLabel');
        l.textContent=this.files[0]?this.files[0].name:'Nothing attached.';
        l.style.color=this.files[0]?'#333':'';
    });
    document.getElementById('editFileInput').addEventListener('change',function(){
        var l=document.getElementById('editAttachLabel');
        l.textContent=this.files[0]?this.files[0].name:'Choose a file to add or replace existing.';
        l.style.color=this.files[0]?'#333':'';
    });

    /* ADD modal */
    document.getElementById('openAddModal').addEventListener('click',function(){
        document.getElementById('addCertForm').reset();
        document.getElementById('addAttachLabel').textContent='Nothing attached.';
        document.getElementById('addAttachLabel').style.color='';
        openModal('addModal');
    });
    document.getElementById('closeAddModal').addEventListener('click',function(){closeModal('addModal');});
    document.getElementById('closeAddModal2').addEventListener('click',function(){closeModal('addModal');});
    document.getElementById('addModal').addEventListener('click',function(e){if(e.target===this)closeModal('addModal');});

    /* ADD submit → stage locally */
    document.getElementById('addCertForm').addEventListener('submit',function(e){
        e.preventDefault(); e.stopPropagation();
        var select=document.getElementById('addSkillSelect');
        var skillId=select.value;
        var skillName=select.options[select.selectedIndex]?select.options[select.selectedIndex].text:'';
        var validFrom=document.getElementById('addValidFrom').value;
        var validTo=document.getElementById('addValidTo').value;
        var fileInput=document.getElementById('addFileInput');
        var fileName=fileInput.files[0]?fileInput.files[0].name:'';
        if(!skillId){showMsg('Please select a Certificate Name.','error');return;}
        var fd=new FormData(this); fd.append('action','add_certification');
        var tempId=tempIdCounter--;
        pendingChanges.push({type:'add',rowId:tempId,formData:fd,displayData:{skillId:skillId,skillName:skillName,validFrom:validFrom,validTo:validTo,fileName:fileName}});
        var tbody=document.getElementById('certTableBody');
        var emptyRow=document.getElementById('certEmptyRow'); if(emptyRow) emptyRow.remove();
        var tr=document.createElement('tr');
        tr.setAttribute('data-id',tempId); tr.setAttribute('data-skill-name',skillName);
        tr.setAttribute('data-from',validFrom); tr.setAttribute('data-to',validTo);
        tr.classList.add('cert-staged-add');
        tr.innerHTML='<td style="padding:13px 18px;vertical-align:middle;font-size:14px;" class="col-skill-name">'+escHtml(skillName)+'<span class="cert-staged-badge badge-staged-add">New</span></td>'+
            '<td style="padding:13px 18px;vertical-align:middle;" class="col-attachments">'+(fileName?'<span style="color:#555;font-size:13px;"><i class="fa fa-file-o me-1"></i>'+escHtml(fileName)+'</span>':'<span class="text-muted" style="font-size:13px;">—</span>')+'</td>'+
            '<td style="padding:13px 18px;vertical-align:middle;font-size:14px;" class="col-from">'+(validFrom?formatDate(validFrom):'—')+'</td>'+
            '<td style="padding:13px 18px;vertical-align:middle;font-size:14px;" class="col-to">'+(validTo?formatDate(validTo):'<span class="text-muted">Indefinite</span>')+'</td>'+
            '<td class="cert-action-col" style="padding:13px 18px;vertical-align:middle;text-align:right;white-space:nowrap;"><button type="button" class="btn btn-sm btn-outline-danger ess-btn-delete-cert" data-id="'+tempId+'" title="Remove"><i class="fa fa-trash"></i></button></td>';
        tbody.appendChild(tr);
        bindDeleteOnRow(tr);
        updatePendingBadge();
        closeModal('addModal');
        showMsg('Staged. Tick the disclaimer and click "Submit for HR Approval".','info');
    });

    /* EDIT modal */
    function bindEditButtons(){
        document.querySelectorAll('.ess-btn-edit-cert').forEach(function(btn){
            btn.addEventListener('click',function(){
                var rowId=this.dataset.id; var row=getRow(rowId); if(!row) return;
                document.getElementById('editSkillRecordId').value=rowId;
                document.getElementById('editSkillName').value=row.dataset.skillName||'';
                document.getElementById('editValidFrom').value=row.dataset.from||'';
                document.getElementById('editValidTo').value=row.dataset.to||'';
                document.getElementById('editAttachLabel').textContent='Choose a file to add or replace existing.';
                document.getElementById('editAttachLabel').style.color='';
                document.getElementById('editFileInput').value='';
                openModal('editModal');
            });
        });
    }
    bindEditButtons();
    document.getElementById('closeEditModal').addEventListener('click',function(){closeModal('editModal');});
    document.getElementById('closeEditModal2').addEventListener('click',function(){closeModal('editModal');});
    document.getElementById('editModal').addEventListener('click',function(e){if(e.target===this)closeModal('editModal');});

    /* EDIT submit → stage locally */
    document.getElementById('editCertForm').addEventListener('submit',function(e){
        e.preventDefault(); e.stopPropagation();
        var rowId=document.getElementById('editSkillRecordId').value;
        var validFrom=document.getElementById('editValidFrom').value;
        var validTo=document.getElementById('editValidTo').value;
        var fileInput=document.getElementById('editFileInput');
        var fileName=fileInput.files[0]?fileInput.files[0].name:'';
        var fd=new FormData(this); fd.append('action','edit_certification');
        pendingChanges=pendingChanges.filter(function(c){return !(c.rowId==rowId&&c.type==='edit');});
        pendingChanges.push({type:'edit',rowId:rowId,formData:fd,displayData:{validFrom:validFrom,validTo:validTo,fileName:fileName}});
        var row=getRow(rowId);
        if(row){
            row.setAttribute('data-from',validFrom); row.setAttribute('data-to',validTo);
            row.querySelector('.col-from').textContent=validFrom?formatDate(validFrom):'—';
            row.querySelector('.col-to').innerHTML=validTo?formatDate(validTo):'<span class="text-muted">Indefinite</span>';
            if(fileName) row.querySelector('.col-attachments').innerHTML='<span style="color:#555;font-size:13px;"><i class="fa fa-file-o me-1"></i>'+escHtml(fileName)+' <small class="text-muted">(pending)</small></span>';
            if(!row.classList.contains('cert-staged-add')){row.classList.add('cert-staged-edit');addRowBadge(row,'edit');}
        }
        updatePendingBadge(); closeModal('editModal');
        showMsg('Edit staged. Tick disclaimer and submit.','info');
    });

    /* DELETE staging */
    function bindDeleteOnRow(row){
        var btn=row.querySelector('.ess-btn-delete-cert'); if(!btn) return;
        btn.addEventListener('click',function(){
            var rowId=this.dataset.id; var isTemp=parseInt(rowId,10)<0;
            if(!confirm('Remove this certification?')) return;
            if(isTemp){
                pendingChanges=pendingChanges.filter(function(c){return c.rowId!=rowId;});
                var r=getRow(rowId); if(r) r.remove();
            } else {
                pendingChanges=pendingChanges.filter(function(c){return !(c.rowId==rowId&&c.type==='edit');});
                pendingChanges=pendingChanges.filter(function(c){return !(c.rowId==rowId&&c.type==='delete');});
                pendingChanges.push({type:'delete',rowId:rowId,formData:null,displayData:{}});
                var r=getRow(rowId);
                if(r){
                    r.classList.remove('cert-staged-edit'); r.classList.add('cert-staged-delete');
                    addRowBadge(r,'delete');
                    r.querySelector('.cert-action-col').innerHTML='<button type="button" class="btn btn-sm btn-outline-secondary ess-btn-undo-delete" data-id="'+rowId+'" title="Undo"><i class="fa fa-undo me-1"></i>Undo</button>';
                    bindUndoOnRow(r);
                }
            }
            updatePendingBadge();
        });
    }

    function bindUndoOnRow(row){
        var btn=row.querySelector('.ess-btn-undo-delete'); if(!btn) return;
        btn.addEventListener('click',function(){
            var rowId=this.dataset.id;
            pendingChanges=pendingChanges.filter(function(c){return !(c.rowId==rowId&&c.type==='delete');});
            var r=getRow(rowId);
            if(r){
                r.classList.remove('cert-staged-delete'); clearRowBadge(r);
                r.querySelector('.cert-action-col').innerHTML='<button type="button" class="btn btn-sm btn-outline-warning ess-btn-edit-cert me-1" data-id="'+rowId+'" title="Edit"><i class="fa fa-pencil"></i></button><button type="button" class="btn btn-sm btn-outline-danger ess-btn-delete-cert" data-id="'+rowId+'" title="Delete"><i class="fa fa-trash"></i></button>';
                bindEditButtons(); bindDeleteOnRow(r);
            }
            updatePendingBadge(); showMsg('Delete undone.','info');
        });
    }

    document.querySelectorAll('#certTableBody tr[data-id]').forEach(function(row){bindDeleteOnRow(row);});

    /* Edit mode toggle */
    function enableEditMode(){
        document.getElementById('openAddModal').style.display='inline-flex';
        document.getElementById('certActionHeader').style.display='';
        document.querySelectorAll('.cert-action-col').forEach(function(td){td.style.display='';});
        var h=document.getElementById('certEmptyHint'); if(h) h.style.display='';
        document.getElementById('certViewActions').style.display='none';
        document.getElementById('certFormActions').style.display='block';
        document.getElementById('certDisclaimer').checked=false;
        var btn=document.getElementById('certDoneBtn'); btn.disabled=true; btn.style.opacity='0.6';
        updatePendingBadge();
    }

    function disableEditMode(){
        document.getElementById('openAddModal').style.display='none';
        document.getElementById('certActionHeader').style.display='none';
        document.querySelectorAll('.cert-action-col').forEach(function(td){td.style.display='none';});
        var h=document.getElementById('certEmptyHint'); if(h) h.style.display='none';
        document.getElementById('certViewActions').style.display='block';
        document.getElementById('certFormActions').style.display='none';
    }

    document.getElementById('certEditBtn').addEventListener('click',enableEditMode);

    document.getElementById('certCancelBtn').addEventListener('click',function(){
        if(pendingChanges.length>0){if(!confirm('Discard all unsaved changes?')) return;}
        pendingChanges=[]; disableEditMode(); location.reload();
    });

    document.getElementById('certDisclaimer').addEventListener('change',function(){
        var btn=document.getElementById('certDoneBtn');
        btn.disabled=!this.checked; btn.style.opacity=this.checked?'1':'0.6';
    });

    /* SUBMIT FOR HR APPROVAL → commit all pending to Odoo (creates PCRs) */
    document.getElementById('certDoneBtn').addEventListener('click',function(){
        if(pendingChanges.length===0){disableEditMode();return;}
        var btn=this; btn.disabled=true;
        btn.innerHTML='<i class="fa fa-spinner fa-spin me-1"></i>Submitting...';
        var changes=pendingChanges.slice(); var errors=[];

        function processNext(index){
            if(index>=changes.length){
                if(errors.length>0){
                    showMsg('Some changes failed: '+errors.join('; '),'error');
                    btn.disabled=false;
                    btn.innerHTML='<i class="fa fa-paper-plane me-1"></i>Submit for HR Approval';
                } else {
                    showMsg('All changes submitted for HR approval successfully!','success');
                    pendingChanges=[];
                    setTimeout(function(){location.reload();},1200);
                }
                return;
            }
            var change=changes[index];
            if(change.type==='delete'){
                var fd=new FormData(); fd.append('action','delete_certification');
                fd.append('skill_record_id',change.rowId); fd.append('csrf_token',csrfToken);
                fetch(BASE_URL,{method:'POST',body:fd})
                    .then(function(r){return r.json();})
                    .then(function(d){if(!d.success)errors.push('Delete: '+(d.error||'failed'));processNext(index+1);})
                    .catch(function(){errors.push('Delete: network error');processNext(index+1);});
            } else if(change.type==='add'){
                fetch(BASE_URL,{method:'POST',body:change.formData})
                    .then(function(r){return r.json();})
                    .then(function(d){if(!d.success)errors.push('Add "'+change.displayData.skillName+'": '+(d.error||'failed'));processNext(index+1);})
                    .catch(function(){errors.push('Add: network error');processNext(index+1);});
            } else if(change.type==='edit'){
                fetch(BASE_URL,{method:'POST',body:change.formData})
                    .then(function(r){return r.json();})
                    .then(function(d){if(!d.success)errors.push('Edit: '+(d.error||'failed'));processNext(index+1);})
                    .catch(function(){errors.push('Edit: network error');processNext(index+1);});
            } else {
                processNext(index+1);
            }
        }
        processNext(0);
    });

}); /* end DOMContentLoaded */
})();
//
